CREATE SCHEMA IF NOT EXISTS stock_qa;

CREATE OR REPLACE FUNCTION stock_qa.clean()
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
  PERFORM set_config('app.tenant_id', 'dev', true);
  DELETE FROM stock.movement WHERE tenant_id = 'dev';
  DELETE FROM stock.article WHERE tenant_id = 'dev';
  DELETE FROM stock.warehouse WHERE tenant_id = 'dev';
  DELETE FROM crm.client WHERE name IN ('Scierie du Jura', 'Quincaillerie Pro') AND tenant_id = 'dev';
END;
$function$;
COMMENT ON FUNCTION stock_qa.clean() IS 'Clean stock seed data';

CREATE OR REPLACE FUNCTION stock_qa.seed()
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_wh_workshop int;
  v_wh_vehicle int;
  v_oak int; v_douglas int; v_screw int; v_bolt int; v_osb int;
  v_wool int; v_oil int; v_glue int; v_bracket int; v_nail int;
  v_supplier_wood int; v_supplier_hardware int;
BEGIN
  PERFORM set_config('app.tenant_id', 'dev', true);

  SELECT id INTO v_supplier_wood FROM crm.client WHERE name = 'Scierie du Jura' AND tenant_id = 'dev';
  IF NOT FOUND THEN
    VALUES ('Scierie du Jura', 'company', 'Arbois', 'dev')
    RETURNING id INTO v_supplier_wood;
  END IF;

  SELECT id INTO v_supplier_hardware FROM crm.client WHERE name = 'Quincaillerie Pro' AND tenant_id = 'dev';
  IF NOT FOUND THEN
    VALUES ('Quincaillerie Pro', 'company', 'Besançon', 'dev')
    RETURNING id INTO v_supplier_hardware;
  END IF;








END;
$function$;
COMMENT ON FUNCTION stock_qa.seed() IS 'Seed demo data for carpenter: 3 warehouses, 10 articles, ~18 movements';

